import React, { useState, useContext } from "react";
import { StoreContext } from "../../context/StoreContext";
import axios from "axios";

function LoginPopup({ setShowLogin }) {
    const { url, setToken } = useContext(StoreContext);
    const [currState, setCurrState] = useState("Login");
    const [data, setData] = useState({ name: "", email: "", password: "" });
    const [showVerificationMessage, setShowVerificationMessage] = useState(false);
    const [unverifiedEmail, setUnverifiedEmail] = useState('');

    const onChangeHandler = (event) => {
        const { name, value } = event.target;
        setData(prev => ({ ...prev, [name]: value }));
    };

    const onLogin = async (event) => {
        event.preventDefault();
        
        let newUrl = url + (currState === "Login" ? "/api/user/login" : "/api/user/register");

        try {
            const response = await axios.post(newUrl, data);

            if (response.data.success) {
                if (currState === "Login") {
                    // Login success
                    setToken(response.data.token);
                    localStorage.setItem("token", response.data.token);
                    alert("Login successful!");
                    setShowLogin(false);
                } else {
                    // Registration success - show verification message
                    setShowVerificationMessage(true);
                }
            } else {
                // Check if needs verification
                if (response.data.requiresVerification) {
                    setUnverifiedEmail(response.data.email);
                    setShowVerificationMessage(true);
                } else {
                    alert(response.data.message);
                }
            }
        } catch (error) {
            console.error("Error:", error);
            alert(error.response?.data?.message || "Something went wrong");
        }
    };

    const resendVerification = async () => {
        try {
            const response = await axios.post(url + "/api/user/resend-verification", {
                email: unverifiedEmail || data.email
            });
            
            if (response.data.success) {
                alert("Verification email resent! Please check your inbox.");
            }
        } catch (error) {
            alert("Failed to resend verification email");
        }
    };

    if (showVerificationMessage) {
        return (
            <div className="login-popup">
                <div className="login-popup-container">
                    <h2>Verify Your Email</h2>
                    <p>We've sent a verification link to:</p>
                    <p><strong>{unverifiedEmail || data.email}</strong></p>
                    <p>Please check your email and click the link to verify your account.</p>
                    <div className="verification-actions">
                        <button onClick={resendVerification}>Resend Email</button>
                        <button onClick={() => setShowLogin(false)}>Close</button>
                    </div>
                </div>
            </div>
        );
    }

    // Rest of your login form JSX...
}
